// ── Helpers ──────────────────────────────────────────────────

function makeTask(overrides: Partial<Parameters<typeof insertTask>[1]> = {}): Parameters<typeof insertTask>[1] {
  return {
    id: `task-${Math.random().toString(36).slice(2, 10)}`,
    command: 'forge run',
    description: 'implement feature X',
    specPath: 'specs/test.md',
    status: 'pending',
    pid: null,
    sessionId: null,
    stdout: [],
    stderr: [],
    exitCode: null,
    cwd: '/tmp/test-repo',
    params: {},
    ...overrides,
  };
}

// ── tasks table migration ─────────────────────────────────────

describe('tasks table migration', () => {
  test('tasks table exists after migration', () => {
    const db = getTestDb();
    const tables = db.query(
      "SELECT name FROM sqlite_master WHERE type='table' AND name='tasks'",
    ).all() as Array<{ name: string }>;
    expect(tables.length).toBe(1);
    db.close();
  });

  test('tasks table has correct columns', () => {
    const db = getTestDb();
    const info = db.query('PRAGMA table_info(tasks)').all() as Array<{ name: string }>;
    const columns = info.map(c => c.name);
    expect(columns).toContain('id');
    expect(columns).toContain('command');
    expect(columns).toContain('description');
    expect(columns).toContain('specPath');
    expect(columns).toContain('status');
    expect(columns).toContain('pid');
    expect(columns).toContain('sessionId');
    expect(columns).toContain('stdout');
    expect(columns).toContain('stderr');
    expect(columns).toContain('exitCode');
    expect(columns).toContain('cwd');
    expect(columns).toContain('params');
    expect(columns).toContain('createdAt');
    expect(columns).toContain('updatedAt');
    db.close();
  });

  test('schema version is at least 5 (tasks migration)', () => {
    const db = getTestDb();
    expect(getSchemaVersion(db)).toBeGreaterThanOrEqual(5);
    db.close();
  });

  test('tasks indexes exist', () => {
    const db = getTestDb();
    const indexes = db.query(
      "SELECT name FROM sqlite_master WHERE type='index' AND tbl_name='tasks'",
    ).all() as Array<{ name: string }>;
    const names = indexes.map(i => i.name);
    expect(names).toContain('idx_tasks_status');
    expect(names).toContain('idx_tasks_cwd_command');
    db.close();
  });
});

// ── insertTask ────────────────────────────────────────────────

describe('insertTask', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('inserts task with pending status', () => {
    const task = makeTask({ id: 'task-pending-001', status: 'pending' });
    insertTask(db, task);

    const result = getTaskById(db, 'task-pending-001');
    expect(result).not.toBeNull();
    expect(result!.status).toBe('pending');
  });

  test('serializes stdout as JSON array', () => {
    const task = makeTask({ id: 'task-stdout', stdout: ['line 1', 'line 2', 'line 3'] });
    insertTask(db, task);

    const result = getTaskById(db, 'task-stdout');
    const parsed = JSON.parse(result!.stdout) as string[];
    expect(parsed).toEqual(['line 1', 'line 2', 'line 3']);
  });

  test('serializes stderr as JSON array', () => {
    const task = makeTask({ id: 'task-stderr', stderr: ['error line'] });
    insertTask(db, task);

    const result = getTaskById(db, 'task-stderr');
    const parsed = JSON.parse(result!.stderr) as string[];
    expect(parsed).toEqual(['error line']);
  });

  test('serializes params as JSON object', () => {
    const task = makeTask({ id: 'task-params', params: { specPath: 'specs/a.md', model: 'opus', extraArgs: ['--fix'] } });
    insertTask(db, task);

    const result = getTaskById(db, 'task-params');
    const parsed = JSON.parse(result!.params) as Record<string, unknown>;
    expect(parsed.specPath).toBe('specs/a.md');
    expect(parsed.model).toBe('opus');
    expect(parsed.extraArgs).toEqual(['--fix']);
  });

  test('defaults to empty arrays for stdout and stderr', () => {
    const task = makeTask({ id: 'task-empty-io', stdout: undefined, stderr: undefined });
    // Remove explicit undefined fields since makeTask provides defaults
    insertTask(db, makeTask({ id: 'task-empty-io-2', stdout: [], stderr: [] }));
    const result = getTaskById(db, 'task-empty-io-2');
    expect(JSON.parse(result!.stdout)).toEqual([]);
    expect(JSON.parse(result!.stderr)).toEqual([]);
  });

  test('sets createdAt and updatedAt timestamps', () => {
    const before = new Date().toISOString();
    const task = makeTask({ id: 'task-timestamps' });
    insertTask(db, task);
    const after = new Date().toISOString();

    const result = getTaskById(db, 'task-timestamps');
    expect(result!.createdAt >= before).toBe(true);
    expect(result!.createdAt <= after).toBe(true);
    expect(result!.updatedAt >= before).toBe(true);
  });

  test('stores null pid initially', () => {
    const task = makeTask({ id: 'task-null-pid' });
    insertTask(db, task);
    const result = getTaskById(db, 'task-null-pid');
    expect(result!.pid).toBeNull();
  });
});

