// ── updateTaskStatus ──────────────────────────────────────────

describe('updateTaskStatus', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('transitions pending to running', () => {
    const task = makeTask({ id: 'task-status-run' });
    insertTask(db, task);

    updateTaskStatus(db, 'task-status-run', 'running');
    const result = getTaskById(db, 'task-status-run');
    expect(result!.status).toBe('running');
  });

  test('transitions running to completed with exitCode 0', () => {
    const task = makeTask({ id: 'task-status-done' });
    insertTask(db, task);
    claimTask(db, 'task-status-done', 1234);

    updateTaskStatus(db, 'task-status-done', 'completed', 0);
    const result = getTaskById(db, 'task-status-done');
    expect(result!.status).toBe('completed');
    expect(result!.exitCode).toBe(0);
  });

  test('transitions running to failed with exitCode 1', () => {
    const task = makeTask({ id: 'task-status-fail' });
    insertTask(db, task);
    claimTask(db, 'task-status-fail', 1234);

    updateTaskStatus(db, 'task-status-fail', 'failed', 1);
    const result = getTaskById(db, 'task-status-fail');
    expect(result!.status).toBe('failed');
    expect(result!.exitCode).toBe(1);
  });

  test('refreshes updatedAt (heartbeat)', async () => {
    const task = makeTask({ id: 'task-heartbeat' });
    insertTask(db, task);
    const original = getTaskById(db, 'task-heartbeat')!.updatedAt;

    await new Promise(r => setTimeout(r, 15));
    updateTaskStatus(db, 'task-heartbeat', 'running');

    const updated = getTaskById(db, 'task-heartbeat')!.updatedAt;
    expect(updated >= original).toBe(true);
  });
});

