// ── markStaleTasks ────────────────────────────────────────────

describe('markStaleTasks', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('marks running tasks older than TTL as failed', () => {
    const task = makeTask({ id: 'task-stale-001', status: 'pending' });
    insertTask(db, task);
    claimTask(db, 'task-stale-001', 99999);

    // Back-date to simulate staleness
    db.run("UPDATE tasks SET updatedAt = '2020-01-01T00:00:00.000Z' WHERE id = 'task-stale-001'");
    markStaleTasks(db, 60 * 60 * 1000); // 1 hour TTL

    const result = getTaskById(db, 'task-stale-001');
    expect(result!.status).toBe('failed');
  });

  test('does not affect recently-updated running tasks', () => {
    const task = makeTask({ id: 'task-fresh-001', status: 'pending' });
    insertTask(db, task);
    claimTask(db, 'task-fresh-001', 99999);
    // updatedAt is current — should not be marked stale

    markStaleTasks(db, 60 * 60 * 1000);
    const result = getTaskById(db, 'task-fresh-001');
    expect(result!.status).toBe('running');
  });

  test('does not affect completed or failed tasks', () => {
    const task = makeTask({ id: 'task-done-002', status: 'pending' });
    insertTask(db, task);
    updateTaskStatus(db, 'task-done-002', 'completed', 0);
    db.run("UPDATE tasks SET updatedAt = '2020-01-01T00:00:00.000Z' WHERE id = 'task-done-002'");

    markStaleTasks(db, 60 * 60 * 1000);
    const result = getTaskById(db, 'task-done-002');
    expect(result!.status).toBe('completed');
  });

  test('does not affect pending tasks (only running)', () => {
    const task = makeTask({ id: 'task-pending-stale', status: 'pending' });
    insertTask(db, task);
    db.run("UPDATE tasks SET updatedAt = '2020-01-01T00:00:00.000Z' WHERE id = 'task-pending-stale'");

    markStaleTasks(db, 60 * 60 * 1000);
    const result = getTaskById(db, 'task-pending-stale');
    expect(result!.status).toBe('pending'); // pending not affected
  });
});

// ── getPendingTasks ───────────────────────────────────────────

describe('getPendingTasks', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('returns pending tasks in FIFO order (oldest first)', () => {
    insertTask(db, makeTask({ id: 'task-fifo-a', status: 'pending' }));
    db.run("UPDATE tasks SET createdAt = '2026-01-01T10:00:00Z' WHERE id = 'task-fifo-a'");

    insertTask(db, makeTask({ id: 'task-fifo-b', status: 'pending' }));
    db.run("UPDATE tasks SET createdAt = '2026-01-01T12:00:00Z' WHERE id = 'task-fifo-b'");

    insertTask(db, makeTask({ id: 'task-fifo-c', status: 'pending' }));
    db.run("UPDATE tasks SET createdAt = '2026-01-01T11:00:00Z' WHERE id = 'task-fifo-c'");

    const rows = getPendingTasks(db, 10);
    expect(rows[0].id).toBe('task-fifo-a');
    expect(rows[1].id).toBe('task-fifo-c');
    expect(rows[2].id).toBe('task-fifo-b');
  });

  test('respects limit parameter', () => {
    for (let i = 0; i < 6; i++) {
      insertTask(db, makeTask({ id: `task-lim-${i}`, status: 'pending' }));
    }
    const rows = getPendingTasks(db, 3);
    expect(rows.length).toBe(3);
  });

  test('does not return running tasks', () => {
    const task = makeTask({ id: 'task-running', status: 'pending' });
    insertTask(db, task);
    claimTask(db, 'task-running', 1234);

    const rows = getPendingTasks(db, 10);
    expect(rows.find(t => t.id === 'task-running')).toBeUndefined();
  });

  test('returns empty array when no pending tasks', () => {
    const rows = getPendingTasks(db, 10);
    expect(rows).toEqual([]);
  });
});

// ── claimTask ─────────────────────────────────────────────────

describe('claimTask', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('successfully claims a pending task', () => {
    const task = makeTask({ id: 'task-claim-001', status: 'pending' });
    insertTask(db, task);

    const claimed = claimTask(db, 'task-claim-001', 5678);
    expect(claimed).toBe(true);

    const result = getTaskById(db, 'task-claim-001');
    expect(result!.status).toBe('running');
    expect(result!.pid).toBe(5678);
  });

  test('returns false when task is already running (prevents double-claim)', () => {
    const task = makeTask({ id: 'task-double-claim', status: 'pending' });
    insertTask(db, task);

    claimTask(db, 'task-double-claim', 1111); // first executor claims it
    const second = claimTask(db, 'task-double-claim', 2222); // second executor fails

    expect(second).toBe(false);
    const result = getTaskById(db, 'task-double-claim');
    expect(result!.pid).toBe(1111); // first claim's PID preserved
  });

  test('returns false for non-existent task', () => {
    const result = claimTask(db, 'task-does-not-exist', 9999);
    expect(result).toBe(false);
  });

  test('returns false for completed task', () => {
    const task = makeTask({ id: 'task-claim-done', status: 'pending' });
    insertTask(db, task);
    updateTaskStatus(db, 'task-claim-done', 'completed', 0);

    const result = claimTask(db, 'task-claim-done', 9999);
    expect(result).toBe(false);
  });
});

// ── getActiveTaskByCommandAndCwd ──────────────────────────────

describe('getActiveTaskByCommandAndCwd', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('returns null when no active tasks', () => {
    const result = getActiveTaskByCommandAndCwd(db, 'forge pipeline', '/repo');
    expect(result).toBeNull();
  });

  test('returns pending task for matching command and cwd', () => {
    const task = makeTask({ id: 'task-active-pending', command: 'forge pipeline', cwd: '/repo', status: 'pending' });
    insertTask(db, task);

    const result = getActiveTaskByCommandAndCwd(db, 'forge pipeline', '/repo');
    expect(result).not.toBeNull();
    expect(result!.id).toBe('task-active-pending');
  });

  test('returns running task for matching command and cwd', () => {
    const task = makeTask({ id: 'task-active-running', command: 'forge run', cwd: '/my/repo', status: 'pending' });
    insertTask(db, task);
    claimTask(db, 'task-active-running', 1234);

    const result = getActiveTaskByCommandAndCwd(db, 'forge run', '/my/repo');
    expect(result).not.toBeNull();
  });

  test('returns null for completed tasks', () => {
    const task = makeTask({ id: 'task-active-done', command: 'forge run', cwd: '/repo', status: 'pending' });
    insertTask(db, task);
    updateTaskStatus(db, 'task-active-done', 'completed', 0);

    const result = getActiveTaskByCommandAndCwd(db, 'forge run', '/repo');
    expect(result).toBeNull();
  });

  test('returns null for failed tasks', () => {
    const task = makeTask({ id: 'task-active-failed', command: 'forge run', cwd: '/repo', status: 'pending' });
    insertTask(db, task);
    updateTaskStatus(db, 'task-active-failed', 'failed', 1);

    const result = getActiveTaskByCommandAndCwd(db, 'forge run', '/repo');
    expect(result).toBeNull();
  });

  test('does not match different cwd', () => {
    const task = makeTask({ id: 'task-wrong-cwd', command: 'forge run', cwd: '/repo-a', status: 'pending' });
    insertTask(db, task);

    const result = getActiveTaskByCommandAndCwd(db, 'forge run', '/repo-b');
    expect(result).toBeNull();
  });

  test('does not match different command', () => {
    const task = makeTask({ id: 'task-wrong-cmd', command: 'forge audit', cwd: '/repo', status: 'pending' });
    insertTask(db, task);

    const result = getActiveTaskByCommandAndCwd(db, 'forge run', '/repo');
    expect(result).toBeNull();
  });
});

